INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('public-health-specialist-moex-00837', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '傳統以調查資料或生命、社會統計資料了解社區問題進行社區診斷，常面臨物力、人力資源 不夠而無法解決問題。為了解決這種困境，學者建議改以資產為本的社區發展模式，有關此 模式之敘述，下列何者錯誤？', '["此模式以增能為基礎", "此模式著重在社區的資產、優勢與潛力之發掘", "社區資產不包括個人之天賦、能力與專業", "此模式所指之主要資源為在社區內，最容易被使用且為社區居民所控制之資源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00838', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '健康受不同的因素所影響，它們統稱為健康的決定因素。其中「這個層面因素往往互相影響， 非個人力量可以控制。需要綜合和多元化的公共衛生措施與介入才能為健康帶來正面的影響」 是屬於何種層面因素？', '["個人生活方式因素層面", "社交和社區網絡層面", "社會、經濟、文化和環境狀況層面", "年齡、性別及遺傳因素層面"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00839', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列有關健康不平等敘述，何者錯誤？', '["貧窮地區國家與先進富有國家在「健康差異」的比較，「人口平均餘命」是其中一項具體指標", "「不健康」主要歸因於個人特質或是生活方式的選擇，民眾若能具備充足的健康知識、正 確的態度，以及實踐健康行為，始能解決健康不平等的問題", "1839年英國統計局發現「貧窮地區死亡人數較多」，此統計數據驗證了社會階層與健康不 平等兩者之關連", "健康不平等現象主要是由於社會經濟因素的不平等所造成"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00840', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '傳播理論中的知溝理論（KnowledgeGap），對公共衛生專業者在健康傳播上的啟發為下列何者？', '["媒體中的吸菸畫面會強化青少年吸菸行為", "政府單位應重視與民眾溝通Covid-19的防疫議題", "可應用大眾媒體的影響力來促成健康公共政策的制定", "健康訊息及管道應考量不同對象特質與需求進行設計"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00841', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '創新擴散（InnovationDiffusion）是將一個創新的事物傳遞出去的過程，這個過程發生在某個 社會系統，利用某種溝通管道，而且經過一段時間；也就是說它所傳遞的是新的事物，參與 在傳遞過程當中的人有所創新，並共同分享，以期達到共識。下列何者不是創新擴散的要素？', '["時間", "社會系統", "溝通管道", "獲利金額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00842', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', 'House在1981年提出「社會支持（SocialSupport）」可分為四種類型，其中「針對問題提出忠 告、建議和資訊」是屬於何種類型？', '["資訊性支持", "工具性支持", "評價性支持", "情感性支持"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00843', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '社會行銷（socialmarketing）指的是將市場行銷（commercialmarketing）的原則與技巧應用在 社會單位，藉以提升社會目標、理念和改變行為模式。下列有關社會行銷的敘述，何者錯誤？', '["社會行銷（socialmarketing）是應用市場行銷（commercialmarketing）的原則與技巧，以提 升和改變行為模式", "所謂行銷組合4P是指產品（Product）、價格（Price）、計畫（Plan）及促銷（Promotion）", "健康行為改變、預防傷害、保護環境及社區健康等議題，是社會行銷常應用的公眾議題領域", "社會行銷可被視為一種改變社會的管理技術（asocialchangemanagementtechnology）或有 力的社會變遷途徑（powerfulapproachtosocialchange）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00844', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某人對他的醫師相當依賴，覺得自己的健康主要掌控在醫師手中，此人之健康決控（health locusofcontrol,HLOC）屬於下列那一種？', '["內在的健康決控（internalHLOC）", "權力他人的健康決控（powerfulotherHLOC）", "靠運氣的健康決控（chanceHLOC）", "中度的健康決控（medianHLOC）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00845', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '1986年心理學家Bronfenbrenner提出，人的健康行為受到多層次的生態系統之影響甚鉅，其 中有關於個人的生命週期屬於下列那一個系統？', '["微系統（micro-system）", "中系統（meso-system）", "外系統（exo-system）", "時間系統（chronosystem）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00846', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '研究顯示，影響婦女接受乳房攝影的常見因素包括：會痛、太忙、不方便等因素，此類因素 屬於健康信念模式中的那一項概念？', '["自覺行動障礙", "自覺利益", "自覺罹患性", "自覺嚴重性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00847', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '防疫中心為鼓勵有疫苗猶豫心態的國人接種COVID-19疫苗，邀請社會中德高望眾者當眾接 種疫苗，此作法可以說是下列那個理論之應用？', '["健康信念模式", "理性行動模式", "社會認知理論", "跨理論模式"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00848', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '比較個人層次及社區層次的健康促進策略模式，下列敘述何者錯誤？', '["健康信念模式（HealthBeliefModel）曾被應用於許多健康行為探討，其偏重描述影響行為 的個人因素，較少考慮社會環境因素對個人行為的影響", "跨理論模式（TranstheoreticalModelofBehaviorChange）解釋個體問題行為改變的過程，認 為行為的改變並非單純的全有或全無，應將行為以改變的階段（stageofchange）加以思考", "理性行動理論及計畫行為理論（TheoryofReasonedAction&TheoryofPlannedBehavior） 認為人具理性思考能力，主要應用於社區層次的健康促進策略", "創新擴散理論（DiffusionofInnovationsModel）由Rogers於1962年提出，創新指的是新的 觀念方法、事物或技術；擴散指的是過程"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00849', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '自我效能是由心理學家AlbertBandura所提出，並成為其社會認知理論（socialcognitivetheory， 簡稱SCT）中的核心概念。有關自我效能（self-efficacy）之論述，下列何者錯誤？', '["自我效能（self-efficacy）指個人對自己評估可依靠外在資源（人力及物力）完成某事的信念", "高度自我效能的人，能夠增加個人與整體的成就與利益；將困難的任務挑戰當作磨練，而 非視為應該避免的威脅", "自我效能與個人擁有的技能無關，而與所擁有的能力程度之自我判斷有關", "自我效能決定個人在特定情境中的行為、思維方式及情緒反應"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00850', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某些健康促進計畫容易被批評為「責備受害者（victimblaming）」，通常原因是什麼？', '["將不健康的生活型態歸因為個人層面的問題", "批判健康服務的不普及影響個人採用醫療資源的意願", "過度強調社會結構對個人健康生活型態的影響", "使用結合個人取向與環境取向的多重策略進行設計"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00851', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '有關跨理論模式（TranstheoreticalModel,TTM）敘述，下列何者錯誤？', '["跨理論模式將行為改變分為五個階段，每個階段各有其身體活動意圖與行為特徵", "社會解放（Socialliberation）是指增加支持行為改變的社會環境，例如倡導（advocacy）以 及充權（empowermentprocedures）策略", "自我解放（Self-liberation）是指個人對改變的信念及對此信念的承諾，例如自我宣誓要運動", "此模式強調健康行為的改變是一種靜態的過程，展現「全有或全無」的現象"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00852', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '有關「計畫行為理論（TheoryofPlanedBehavior,TPB）」之論述，下列何者錯誤？', '["Ajzen提出計畫行為理論（TheoryofPlanedBehavior,TPB），是以理性行為理論（Theoryof ReasonedAction,TRA）為基礎所演進而來", "計畫行為理論較理性行為理論更受學者重視，並被認定為是較完整的行為意圖模式；實證 研究結果顯示，計畫行為理論的預測能力確實較理性行為理論為高", "行為控制知覺（perceivedbehavioralcontrol）乃指個人在採取某一項特定行為時所感受到的 社會壓力，亦即個人知覺到的重要他人（如父母）認為他應否執行該特定行為之壓力", "態度變項是個人對特定行為所抱持的正、負向評價，當個人對行為的態度愈趨正向，其行 為意圖亦將愈高；若愈趨負向，行為意圖則隨之愈低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00853', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列何者不是理性行為理論（TheoryofReasonedAction,TRA）中的建構或成分（component）？', '["主觀規範（subjectivenorm）", "自覺行為控制（perceivedbehavioralcontrol）", "態度（attitude）", "自我效能（selfefficacy）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00854', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '對於社會行為科學研究應用在健康促進方案執行，下列敘述何者錯誤？', '["推動健康促進方案的基本條件，無論地方、國家和全球必須有一定的資金", "參與是重要的要素，群眾應參與健康促進中心的行動和決策過程", "面對健康的未知或新威脅，建立各種各樣的網絡是必要的", "為避免多頭馬車，相較於使用多重策略，運用單一的策略執行健康促進方案，其成效較為 明顯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00855', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '有關健康促進之相關概念，下列敘述何者錯誤？', '["場域策略是健康促進運動最重要的創新", "民眾的參與是健康促進行動能夠永續的關鍵", "五大行動綱領單獨運用比結合運用更為有效", "健康促進強調社區參與及自決能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00856', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '有關PRECEDE-PROCEED模式之運用，下列何者錯誤？', '["此模式非常強調資料的收集，所以相當耗時", "此模式強調要符合目標對象真正的需求", "運用此模式時，一定要從第一階段開始，按步就班的執行資料收集", "可搭配現今科技（如：網路及遠距通訊設備），以縮短計畫之時間及人力成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00857', 'public-health-specialist', 'public-health-specialist-moex-110-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '某巿政府經常給予高齡者職業再訓練，教導高齡者使用新的科技產品。此類活動屬於高齡友 善城市之那一個面向？', '["不老：公民參與及就業", "親老：社會參與", "無礙：戶外空間與建築", "敬老：尊重與社會包容"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:40+00:00", "source_pdf_sha1": "8c0bb75c5abe", "answer_pdf_sha1": "7291190b6646", "source_family": "moex-gov-tw", "moex": {"exam_code": "110180", "c": "401", "s": "1406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "110", "exam_name": "110年專技人員高等考試建築師、24類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)、公共衛生師考試暨普通考試不動產...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
